    // Only keep y-coordinates with at least 2 points (potential horizontal edges)
    const yCoords = Array.from(yToXs.keys()).filter(y => yToXs.get(y)!.length >= 2);
    yCoords.sort((a, b) => a - b);

    let total = 0;

    // For each pair of y-coordinates (y1, y2), count the number of horizontal trapezoids
    for (let i = 0; i < yCoords.length; i++) {
        const y1 = yCoords[i];
        const xList1 = yToXs.get(y1)!;
        xList1.sort((a, b) => a - b);
        const m = xList1.length;

        for (let j = i + 1; j < yCoords.length; j++) {
            const y2 = yCoords[j];
            const xList2 = yToXs.get(y2)!;
            xList2.sort((a, b) => a - b);
            const n = xList2.length;

            // Count the number of common x coordinates between the two y-coordinates
            let common = 0;
            let p1 = 0, p2 = 0;
            while (p1 < m && p2 < n) {
                if (xList1[p1] === xList2[p2]) {
                    common++;
                    p1++;
                    p2++;
                } else if (xList1[p1] < xList2[p2]) {
                    p1++;
                } else {
                    p2++;
                }
            }

            // The number of trapezoids is C(m, 2) * C(n, 2) - C(common, 2)
            const c1 = m * (m - 1) / 2 % MOD;
            const c2 = n * (n - 1) / 2 % MOD;
            const cCommon = common * (common - 1) / 2 % MOD;
            let count = (c1 * c2 % MOD - cCommon + MOD) % MOD;
            total = (total + count) % MOD;
        }
    }

    return total;
}
